def parse_nombre(raw):
    toks = raw.split()
    if len(toks) < 3:
        return {"status": "review", "raw": raw, "given": raw, "apellidos": None}
    return {
        "status": "ok",
        "raw": raw,
        "given": " ".join(toks[:-2]),
        "apellidos": " ".join(toks[-2:]),
    }

for n in ["Madonna", "Ana María Quispe Huamán"]:
    print(parse_nombre(n))
