def normalize_email(raw):
    s = raw.strip().casefold()
    if ' ' in s or s.count('@') != 1:
        raise ValueError('review_error')
    local, domain = s.split('@')
    if not local or not domain:
        raise ValueError('review_error')
    return s

for v in ['  A@B.COM ', '@b.com', 'a@@b.com', 'a b@c.com', 'user+tag@example.com']:
    try:
        print(v, '→', normalize_email(v))
    except ValueError as e:
        print(v, '→', e)
