def tokens(s):
    return set(' '.join(s.split()).casefold().split())

def jaccard(a, b):
    A, B = tokens(a), tokens(b)
    if not A and not B:
        return 1.0
    return len(A & B) / len(A | B)

print(round(jaccard('Ana Quispe', 'Ana Quispe Rojas'), 2))
